import PassKit

@objc(XPCarKeyPassAccessProtocol)
public protocol CarKeyPassAccessProtocol: NSObjectProtocol {
    func setCarkeyEventDelegate(delegate: CarKeyPassEventDelegate?)
    func passIsAvailable() -> CarKeyPassEventError
    func getCurrentCarKeyId() -> String?
    func getCurrentCarKeyInfo() -> Dictionary<String, Any>?
    func remoteCarKeyChanged(keyIdList: [String]?, uid: UInt64) -> Void
    func startCarKeyPair(password: String, autoMakerId: String, profileTemplateId: String, brandName: String, supportedRadioTechnologies: UInt, complete: @escaping (CarKeyPassEventError, UIViewController?) -> Void)
    func startCarKeyShare(isPromptToShareUrl: Bool, complete: @escaping (CarKeyPassEventError, UIViewController?) -> Void)
    func handleAppRunState(isInBackground: Bool)
}

@objc(XPCarKeyPassEventDelegate)
public protocol CarKeyPassEventDelegate: NSObjectProtocol {
    func carKeyAddPassResult(error: CarKeyPassEventError)
    func carKeySharePassResult(error: CarKeyPassEventError)
    func carKeyShareDidCreateShare(universalShareURL: NSURL?, activationCode: NSString?)
}

protocol CarKeyPassManageDelegate: NSObjectProtocol {
    func localPassDidRefresh()
}

