import Foundation
import XPVehicleSDK

public typealias XPCarKeyInteractionCallBack<T> = (_ error: CarKeyPassEventError, _ data: T?) -> Void

@objc(XPCarKeyPassInteraction)
public protocol CarKeyPassInteraction: NSObjectProtocol {

